namespace Forge.Api.Data.TrainingContent;

/// <summary>
/// Core training for the lead-scoring admin surfaces: Lead Sources catalog
/// (/admin/lead-sources), ICP Rubrics + weighted dimensions (/admin/icp-rubrics),
/// and Entity Completeness requirement rows (/admin/entity-completeness).
///
/// Fills the major-gap "taught: no" coverage identified in the training audit:
/// the catalog CRUD, the immutable Code + nightly Quality Score, the
/// single-default rubric invariant, weighted-dimension scoring (rubric →
/// Lead.IcpScore → work-queue ordering), MatchSpec / predicate JSON authoring,
/// and the i18n-key wiring on completeness rows.
/// </summary>
public class LeadScoringTraining : TrainingContentBase
{
    public LeadScoringTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Lead Sources & Quality Scores (Article) ──────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Sources & Quality Scores",
            Slug = "lead-sources-overview",
            Summary = "Manage the Lead Sources catalog: a Name plus an immutable Code, the nightly auto-computed Quality Score, and why you deactivate a source instead of deleting it once leads are attributed to it.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/admin/lead-sources"]""",
            Tags = """["lead-scoring","lead-sources","admin","leads"]""",
            ContentJson = """{"body":"## Lead Sources & Quality Scores\n\nThe **Lead Sources** catalog (Admin → Lead Sources) is the authoritative list of where your leads come from — trade shows, a purchased list, the website contact form, a referral partner, a specific ad campaign. Every lead can be attributed to a source, and bulk-intake stamps that attribution automatically. Cataloging your sources lets you measure which channels actually produce business and which deliver garbage.\n\n### Name vs Code — and why Code is immutable\n\nA lead source has two identifiers:\n\n- **Name** — the human-readable label (e.g., 'IMTS 2026 Trade Show', 'Website Contact Form'). Fully editable; rename it whenever you like.\n- **Code** — a short, stable identifier (e.g., `imts-2026`, `web-contact`). The Code is set once when you create the source and **can never be changed afterward**. In the edit dialog the Code field is disabled.\n\nThe Code is the natural key that the rest of the system binds to: bulk-import pipelines map a column to a source Code, web forms and referrer URLs carry the Code, and historical leads point at it. If the Code could change, every one of those bindings would silently break. So choose it carefully at create time. The Code accepts letters, digits, hyphens, and underscores only.\n\n### The Quality Score\n\nEvery source carries a **Quality Score** from 0 to 100. This is **not** something you type in — it is computed automatically by a nightly background job from the *outcomes* of that source's leads. You cannot edit it; the column is read-only on this screen.\n\nThe score is a rolling measure of how good a source's leads turn out to be:\n\n- Every source starts at a neutral **50**.\n- Leads that **convert** to customers pull the score **up** (the strongest positive signal).\n- Leads that **engage** (a real two-way conversation) pull it **up** modestly.\n- Leads marked **Bad Data** or **Suppressed** (do-not-contact) pull it **down**.\n- Leads marked **Lost** pull it **down** modestly.\n- Only leads from roughly the **last 180 days** count — that window is what makes the score *rolling*, so a source that improved (or degraded) recently is reflected, not its all-time history.\n\nThe final number is clamped to 0–100. In the table the score is color-coded: green at 70+ (a strong source), amber from 40–69 (mixed), red below 40 (this channel is delivering leads that don't pan out — investigate the list provider or campaign).\n\nBecause the job runs nightly, the score lags real-time. A brand-new source sits at 50 until its leads accumulate outcomes and the next run picks them up.\n\n### Creating and editing a source\n\nClick **New Source** in the toolbar. Provide a **Name** and a **Code** (both required), and optionally a **Description** explaining what the source is. Save. When you edit an existing source you can change the Name, Description, and the **Active** toggle — but not the Code.\n\n### Deactivate vs Delete\n\nThere are two ways to retire a source, and they are not interchangeable:\n\n- **Deactivate** (set the Active toggle off) — the source stays in the system and stays attached to all its historical leads, but it no longer appears as a choice for new intake. Use this whenever a source has *any* leads attributed to it. Historical attribution survives, so your reporting and the source's Quality Score stay intact.\n- **Delete** (the trash icon) — permanently removes the source. The server **blocks the delete** with an error if any leads are linked to it. This is a guard rail: you can only hard-delete a source that was created by mistake and never used. If leads exist, the system tells you to deactivate instead.\n\nThe practical rule: **if a source has ever been used, deactivate it; only delete the truly-empty mistakes.**\n\n### How this feeds the rest of the system\n\nThe source on a lead is one of the fields the ICP scoring job can match against (see *ICP Rubrics & Weighted Dimensions*), and the per-source Quality Score helps you decide where to spend your lead-generation budget. Sources, rubrics, and completeness rules together make up the lead-scoring admin area.","sections":[]}"""
        });

        // ── ICP Rubrics & Weighted Dimensions (Article) ──────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "ICP Rubrics & Weighted Dimensions",
            Slug = "icp-rubrics-overview",
            Summary = "Build an Ideal Customer Profile rubric out of weighted dimensions, understand the single-default invariant, and follow the end-to-end path: rubric → nightly Lead.IcpScore → work-queue ordering.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","icp","rubrics","admin","leads"]""",
            ContentJson = """{"body":"## ICP Rubrics & Weighted Dimensions\n\nAn **ICP rubric** (Ideal Customer Profile) is a scoring sheet that grades how well a lead fits the kind of customer you actually want. Admin → ICP Rubrics is where you build and tune those rubrics. The output is a 0–100 **fit score** stamped on every active lead, which the rep work-queue uses to surface the best-fit leads first.\n\n### The end-to-end picture (read this first)\n\nIt's worth understanding the whole chain before touching the editor:\n\n1. You define a **rubric** made of weighted **dimensions** (industry, company size, location, etc.).\n2. One rubric is flagged **Default** (and **Active**).\n3. A **nightly job** evaluates the default rubric's dimensions against every active lead, sums the weights of the dimensions that match, normalizes the total to 0–100, and writes it to **`Lead.IcpScore`**.\n4. The **lead work-queue** orders leads by that score, so reps spend their time on the highest-fit prospects.\n\nNothing scores in real time — the score you see on a lead is the cached result of the last nightly run. Edit a rubric today, and the new weights take effect on the next run.\n\n### Rubric header fields\n\nClick **New Rubric** (or a row to edit). A rubric has:\n\n- **Name** (required) — e.g., 'Aerospace Machining ICP'.\n- **Description** — free-text reminder of who this rubric targets.\n- **Active** — whether the rubric is in play at all.\n- **Default** — whether this is *the* rubric the nightly scoring job uses.\n\n### The single-default invariant\n\nThe scoring job uses exactly one rubric: the one that is both **Active** and **Default**. The server enforces that **at most one rubric is the default** — when you mark a rubric as Default, the previously-default rubric is automatically un-defaulted in the same save. You never have to hunt down the old default and turn it off; flipping the flag on a new rubric is enough.\n\nA consequence worth internalizing: if **no** rubric is Active+Default, or the default rubric has **no dimensions**, or all its dimensions have **zero/negative** weight, the nightly job logs that it skipped and **no scores are written**. A rubric with dimensions but no positive weight can't produce a meaningful 0–100 score.\n\n### Dimensions — the weighted scoring rows\n\nInside the rubric editor is a **Dimensions** section. Each dimension is one criterion the lead is graded on. Add as many as you need with **Add Dimension**; each row has four fields:\n\n- **Field Key** (required) — the lead/account attribute this dimension looks at. Common keys: `industry`, `employeeCount`, `state`, `companyName`, `source`. (This is a documentation/intent field that pairs with the Match Spec — see the Match Spec walkthrough for exactly how a lead is matched.)\n- **Label** — a human description so you remember what the row targets ('Target aerospace & defense').\n- **Match Spec** — a small JSON snippet describing what counts as a *hit*. Covered in depth in *Authoring ICP Match Specs*.\n- **Weight** (required) — the points this dimension contributes when it matches. **Positive** weights reward a fit; **negative** weights penalize an anti-fit (e.g., −10 for an industry you don't serve).\n\n### How the score is computed\n\nFor each lead, the job walks every dimension, and for the ones whose Match Spec matches the lead, it adds that dimension's weight. The running total is divided by the **sum of all positive weights** (the maximum achievable), multiplied by 100, and clamped to 0–100. So:\n\n- A lead that hits your highest-weighted dimensions lands near 100.\n- A lead that hits nothing (or trips negative-weight penalties) lands near 0.\n- The *relative* weights are what matter — doubling every weight changes nothing, because the denominator scales with it.\n\n### Saving\n\nThe editor saves the header and the dimensions together in one action. Deleting a dimension row and saving removes it. Because several dimensions are usually tuned at once, the save is one round-trip and produces one rolled-up activity entry rather than one per row.\n\n### Where to go next\n\nThe Match Spec column is the one part of a dimension that has real syntax. *Authoring ICP Match Specs* walks through the exact JSON shapes the scoring job understands.","sections":[]}"""
        });

        // ── Authoring ICP Match Specs (Walkthrough) ──────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Authoring ICP Match Specs",
            Slug = "icp-match-specs-walkthrough",
            Summary = "A guided tour of the ICP Rubrics page that explains how to author the Match Spec JSON on each dimension — string lists, industry/state objects, and numeric size ranges — and how the nightly job evaluates them.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","icp","match-spec","walkthrough","admin"]""",
            ContentJson = """{"appRoute":"/admin/icp-rubrics","startButtonLabel":"Tour ICP Rubrics","steps":[{"element":".toolbar__hint","popover":{"title":"ICP Rubrics","description":"This page lists every Ideal Customer Profile rubric. The nightly scoring job uses the one rubric that is both Active and Default to grade every active lead from 0 to 100. The score it produces drives the order of the rep work-queue.","side":"bottom"}},{"element":"[data-testid='icp-rubric-new-btn']","popover":{"title":"New Rubric","description":"Click here to create a rubric, or click an existing row to edit it. The editor dialog manages the rubric header (Name, Description, Active, Default) AND its weighted dimensions together — they save in one action.","side":"left"}},{"element":"app-data-table","popover":{"title":"The rubric list","description":"Each row shows the rubric's name, its dimension count, and chips for Default and Active. Only one rubric can be the Default — marking a new one default automatically un-defaults the old one. The Dimensions count tells you at a glance whether a rubric is actually configured to score anything.","side":"top"}},{"element":"app-data-table","popover":{"title":"Dimensions and the Match Spec","description":"Open a rubric to reveal its Dimensions section. Each dimension has a Field Key, a Label, a Weight, and a Match Spec. The Match Spec is the only field with real syntax: it is a small JSON snippet that tells the nightly job what counts as a HIT for that dimension. The next steps explain the three shapes the job understands.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match Spec shape 1 — a string list","description":"A JSON array of strings, e.g. [\"aerospace\",\"defense\",\"machining\"], is a case-insensitive SUBSTRING match. The job tests each string against the lead's company name, source, email, and (if the lead is on an Account) the account's industry, state, size bracket, and name. If ANY string is found inside ANY of those, the dimension hits and its weight is added.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match Spec shape 2 — keyed objects","description":"An object targets a specific account field exactly. { \"industries\": [\"Aerospace\",\"Defense\"] } matches the account's Industry exactly (case-insensitive). { \"states\": [\"CA\",\"WA\",\"TX\"] } matches the account's State. Use these when you want a precise field match instead of a loose substring search.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match Spec shape 3 — a numeric range","description":"{ \"min\": 50, \"max\": 500 } matches when the account's numeric size bracket falls in [min, max] inclusive — e.g. companies with 50–500 employees. Anything the job can't parse (malformed JSON, an unknown shape, or a blank spec) is simply treated as NO match; the admin sees the raw spec in the editor and can fix it.","side":"top"}},{"element":"[data-testid='icp-rubric-new-btn']","popover":{"title":"Tune, save, wait for the run","description":"Set positive weights on the dimensions you want to reward and negative weights to penalize an anti-fit. Save the rubric. The change takes effect on the next nightly run, which recomputes Lead.IcpScore for every active lead and re-orders the work-queue accordingly.","side":"left"}}]}"""
        });

        // ── Entity Completeness Requirements Admin (Article) ──────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Entity Completeness Requirements",
            Slug = "entity-completeness-overview",
            Summary = "Author capability-indexed completeness rules for Vendor, Part, and Customer records: what a requirement row is, the predicate JSON DSL, the i18n display/message keys, and how the completeness chip consumes them.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/entity-completeness"]""",
            Tags = """["lead-scoring","entity-completeness","predicates","admin"]""",
            ContentJson = """{"body":"## Entity Completeness Requirements\n\nAdmin → Entity Completeness lets you define what it means for a record to be **complete enough to be used**. Each row answers one question: *\"for an entity of type X to participate in the workflows that capability Y unlocks, what must be true about that record?\"* The completeness chip on Vendor, Part, and Customer detail screens reads these rows and lists exactly what's still missing.\n\nThis catalog ships **empty** by design — the requirements an install needs depend on which capabilities it has turned on, so you author the rows yourself rather than fighting a pre-seeded set that doesn't fit.\n\n### What one requirement row contains\n\nClick **New Requirement** to open the dialog. A row has these fields:\n\n- **Entity Type** (required) — which record this applies to: **Vendor**, **Part**, or **Customer**.\n- **Capability Code** (required) — a capability from the catalog, e.g. `CAP-MD-VENDORS`, `CAP-P2P-PO`. The requirement only matters in the context of that capability.\n- **Requirement Id** (required) — a short stable id for *this specific requirement* within the (Entity Type, Capability) pair, e.g. `tax-id`, `payment-terms`, `billing-address`. This is what lets one capability declare several discrete requirements that each show up individually in the missing-fields list.\n- **Predicate** (required) — the JSON rule that must evaluate **true** for the record to satisfy this requirement (the syntax is below).\n- **Display Name Key** (required) — an **i18n key** for the short label shown in the chip popover (e.g. `entityCompleteness.fields.taxId` → 'Tax ID').\n- **Missing Message Key** (required) — an **i18n key** for the fuller explanation shown when the requirement isn't met (e.g. 'Vendor needs a federal tax ID before being added to a purchase order').\n- **Sort Order** — display order within the (Entity Type, Capability) grouping.\n\nBecause Entity Type + Capability Code + Requirement Id are **unique together**, you add multiple rows — one per discrete requirement — rather than cramming several checks into one predicate, so each shows up as its own line item in the chip.\n\n### The predicate DSL\n\nThe Predicate is JSON evaluated by the shared predicate engine (the same one the guided-workflow readiness gates use). Every predicate is an object with a `type`. Field names are written in **camelCase** and are matched against the loaded entity's properties. The available operators:\n\n- **`fieldPresent`** — the value is not null, and for strings, not empty. `{ \"type\": \"fieldPresent\", \"field\": \"taxId\" }`\n- **`fieldEquals`** — strict equality. `{ \"type\": \"fieldEquals\", \"field\": \"creditTerms\", \"value\": \"Net30\" }`\n- **`fieldCompare`** — numeric comparison with an op of `gt` / `lt` / `gte` / `lte` / `ne`. `{ \"type\": \"fieldCompare\", \"field\": \"leadTimeDays\", \"op\": \"gt\", \"value\": 0 }`\n- **`relationExists`** — a child collection has at least `minCount` items. `{ \"type\": \"relationExists\", \"field\": \"addresses\", \"minCount\": 1 }`\n- **`relationCountCompare`** — the collection size compared by op + value.\n- **`all`** / **`any`** / **`not`** — boolean composition over nested predicates. `all` and `any` take a `predicates` array; `not` takes one nested predicate.\n\nA composite example — a vendor must have a tax id AND at least one address:\n\n```\n{ \"type\": \"all\", \"predicates\": [\n  { \"type\": \"fieldPresent\", \"field\": \"taxId\" },\n  { \"type\": \"relationExists\", \"field\": \"addresses\", \"minCount\": 1 }\n] }\n```\n\nImportant safety behavior: an **unknown field, unknown operator, or malformed JSON short-circuits to `false`** (the requirement is treated as *not met*) and logs a single warning. The record will simply look incomplete until you fix the predicate — it never crashes the chip.\n\n### Wiring the i18n keys\n\nThe Display Name Key and Missing Message Key are *keys*, not literal text. For the chip to show real words instead of a raw token, the matching translation entries must exist in the language files (`en.json`, and `es.json` for parity). If a key has no translation, the UI falls back to the raw key string — that's your signal that the wiring is incomplete. Pick a consistent key prefix (the existing convention is `entityCompleteness.fields.*` for labels and `entityCompleteness.messages.*` for explanations) so the keys stay organized.\n\n### How the chip uses all this\n\nWhen a user opens a Vendor / Part / Customer, the completeness evaluator pulls every requirement row for that entity type whose capability is enabled, loads the record, and runs each predicate. Requirements that evaluate **false** become the chip's missing-fields list — each rendered with its Display Name (and the fuller Missing Message in the popover), ordered by Sort Order. Requirements that pass are silent. This is also the foundation for future hard blocks (e.g., refusing to add a vendor to a PO until its PO-required fields are present).\n\n### Filtering and editing\n\nThe page toolbar filters the list by Entity Type and by Capability Code so you can manage a large ruleset. Edit a row with the pencil icon; delete with the trash icon (with a confirm). Editing a predicate takes effect immediately on the next completeness evaluation — there is no nightly job here.","sections":[]}"""
        });

        // ── Authoring a Completeness Requirement (Walkthrough) ────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Authoring a Completeness Requirement",
            Slug = "entity-completeness-walkthrough",
            Summary = "A guided tour of the Entity Completeness admin page: filtering the ruleset, opening the New Requirement dialog, and authoring the entity type, capability code, requirement id, predicate JSON, and i18n keys.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/admin/entity-completeness"]""",
            Tags = """["lead-scoring","entity-completeness","walkthrough","admin"]""",
            ContentJson = """{"appRoute":"/admin/entity-completeness","startButtonLabel":"Tour Entity Completeness","steps":[{"element":"app-toolbar","popover":{"title":"Entity Completeness admin","description":"This page is where you author completeness rules for Vendor, Part, and Customer records. The catalog ships empty — you add the rows your enabled capabilities actually need. The completeness chip on each record reads these rows and lists what's still missing.","side":"bottom"}},{"element":"app-select","popover":{"title":"Filter by entity type","description":"Use this dropdown to narrow the list to Vendor, Part, or Customer rows (or All). As your ruleset grows this is how you find the rows for the record type you're tuning.","side":"bottom"}},{"element":"app-input","popover":{"title":"Filter by capability","description":"Type a capability code (CAP-...) to see only the requirements tied to that capability. Each requirement is scoped to one capability — it only applies when that capability is enabled on the install.","side":"bottom"}},{"element":"[data-testid='ecr-new-btn']","popover":{"title":"New Requirement","description":"Open the authoring dialog. You'll set the Entity Type, the Capability Code, a stable Requirement Id, the predicate JSON, two i18n keys, and a sort order.","side":"left"}},{"element":"app-data-table","popover":{"title":"The requirement rows","description":"Each row is one discrete check. Entity Type + Capability Code + Requirement Id are unique together, so you add several rows — one per requirement — and each surfaces as its own line in the chip's missing-fields list. The Display Name Key and Missing Message Key columns are i18n keys, not literal text.","side":"top"}},{"element":"app-data-table","popover":{"title":"The predicate","description":"The Predicate field holds JSON evaluated by the shared predicate engine: fieldPresent, fieldEquals, fieldCompare, relationExists, and all/any/not composition. Field names are camelCase. A malformed or unknown predicate safely evaluates to false (the record just looks incomplete) — it never breaks the chip.","side":"top"}},{"element":"[data-testid='ecr-new-btn']","popover":{"title":"Don't forget the translations","description":"The Display Name Key and Missing Message Key must have matching entries in the language files (en.json plus es.json for parity). If a key has no translation, the chip renders the raw key token — that's your cue the i18n wiring is incomplete. Use the entityCompleteness.fields.* and entityCompleteness.messages.* prefixes to stay consistent.","side":"left"}}]}"""
        });

        // ── Lead Scoring Admin Field Reference (QuickRef) ─────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Scoring Admin Field Reference",
            Slug = "lead-scoring-field-reference",
            Summary = "Quick reference for the three lead-scoring admin surfaces: Lead Source fields and Quality-Score math, ICP rubric/dimension fields and Match Spec shapes, and Entity Completeness fields with the full predicate DSL.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 6,
            AppRoutes = """["/admin/lead-sources","/admin/icp-rubrics","/admin/entity-completeness"]""",
            Tags = """["lead-scoring","reference","admin"]""",
            ContentJson = """{"title":"Lead Scoring Admin Field Reference","groups":[{"heading":"Lead Sources — Fields","items":[{"label":"Name","value":"Required. Human-readable label. Editable any time."},{"label":"Code","value":"Required, set at create, IMMUTABLE afterward (disabled in the edit dialog). The natural key imports / forms / referrer URLs bind to. Letters, digits, hyphens, underscores only."},{"label":"Description","value":"Optional free text describing the source (max 500 chars)."},{"label":"Quality Score","value":"0–100, READ-ONLY. Auto-computed nightly from lead outcomes — you never type it. Color-coded: green 70+, amber 40–69, red <40."},{"label":"Active","value":"Toggle (edit only). Off = hidden from new intake but kept attached to historical leads."},{"label":"Leads","value":"Count of leads attributed to this source. Drives the delete guard."},{"label":"Created","value":"Creation date, MM/dd/yyyy."}]},{"heading":"Lead Sources — Quality Score math","items":[{"label":"Starting value","value":"50 (neutral) for every source."},{"label":"+5 each","value":"Lead that Converted to a customer (strongest positive)."},{"label":"+2 each","value":"Lead that Engaged (real two-way conversation)."},{"label":"−5 each","value":"Lead marked Bad Data or Suppressed (do-not-contact)."},{"label":"−2 each","value":"Lead marked Lost."},{"label":"Window","value":"Only leads created in the last ~180 days count — this is what makes the score 'rolling'."},{"label":"Clamp","value":"Final score clamped to 0–100. LastScoredAt stamps each nightly run."}]},{"heading":"Lead Sources — Deactivate vs Delete","items":[{"label":"Deactivate","value":"Set Active off. Use whenever the source has ANY leads. Keeps historical attribution + the score."},{"label":"Delete","value":"Trash icon. BLOCKED by the server (error) if any leads are linked. Only for never-used mistakes."}]},{"heading":"ICP Rubric — Header fields","items":[{"label":"Name","value":"Required. Identifies the rubric (max 100 chars)."},{"label":"Description","value":"Optional reminder of who the rubric targets (max 500)."},{"label":"Active","value":"Whether the rubric is in play."},{"label":"Default","value":"Whether THIS is the rubric the nightly job scores against. At most one default — marking a new one un-defaults the old one automatically."},{"label":"Dimensions count","value":"Shown in the list; tells you whether the rubric can actually score anything."}]},{"heading":"ICP Dimension — Row fields","items":[{"label":"Field Key","value":"Required. The lead/account attribute the dimension targets (industry, employeeCount, state, companyName, source). Intent/documentation field paired with Match Spec."},{"label":"Label","value":"Optional human description of what the row targets."},{"label":"Match Spec","value":"JSON describing what counts as a hit (shapes below). Blank/malformed = no match."},{"label":"Weight","value":"Required integer. Positive rewards a fit; negative penalizes an anti-fit. Only positive weights count toward the denominator (max score)."}]},{"heading":"ICP Match Spec — Shapes","items":[{"label":"String array","value":"[\"aerospace\",\"defense\"] — case-insensitive SUBSTRING match against the lead's company name, source, email, and account industry / state / size / name. Any string in any field = hit."},{"label":"{ industries: [...] }","value":"Exact (case-insensitive) match against the linked account's Industry."},{"label":"{ states: [...] }","value":"Exact match against the linked account's State."},{"label":"{ min: N, max: M }","value":"Numeric range [min,max] inclusive against the account's numeric size bracket."},{"label":"Anything else","value":"Unrecognized shape, malformed JSON, or blank = treated as NO match (never an error)."}]},{"heading":"ICP — Scoring math","items":[{"label":"Per lead","value":"Sum the Weight of every dimension whose Match Spec hits."},{"label":"Normalize","value":"hitWeight ÷ (sum of positive weights) × 100, rounded, clamped to 0–100."},{"label":"Written to","value":"Lead.IcpScore (cached column), by the nightly job, for non-Converted / non-Lost leads only."},{"label":"Consumed by","value":"The rep work-queue, which orders leads highest-fit first."},{"label":"Skip conditions","value":"No Active+Default rubric, default rubric has no dimensions, or zero positive weight → job skips, no scores written."}]},{"heading":"Entity Completeness — Row fields","items":[{"label":"Entity Type","value":"Required. Vendor, Part, or Customer."},{"label":"Capability Code","value":"Required. The capability the requirement is scoped to (CAP-MD-VENDORS, CAP-P2P-PO, ...)."},{"label":"Requirement Id","value":"Required. Stable id for THIS check within (Entity Type, Capability). Unique together. e.g. tax-id, payment-terms."},{"label":"Predicate","value":"Required JSON rule that must evaluate true (DSL below)."},{"label":"Display Name Key","value":"Required i18n key for the short chip label. Convention: entityCompleteness.fields.*"},{"label":"Missing Message Key","value":"Required i18n key for the fuller 'why it's missing' text. Convention: entityCompleteness.messages.*"},{"label":"Sort Order","value":"Display order within the (Entity Type, Capability) grouping."}]},{"heading":"Predicate DSL — Operators","items":[{"label":"fieldPresent","value":"{ type:'fieldPresent', field:'taxId' } — value not null (and non-empty for strings)."},{"label":"fieldEquals","value":"{ type:'fieldEquals', field:'creditTerms', value:'Net30' } — strict equality."},{"label":"fieldCompare","value":"{ type:'fieldCompare', field:'leadTimeDays', op:'gt', value:0 } — op is gt/lt/gte/lte/ne."},{"label":"relationExists","value":"{ type:'relationExists', field:'addresses', minCount:1 } — child collection has ≥ minCount items."},{"label":"relationCountCompare","value":"Collection size compared by op + value."},{"label":"all / any / not","value":"Boolean composition. all/any take a 'predicates' array; not takes one nested predicate."},{"label":"Field casing","value":"camelCase in JSON; the engine title-cases to reflect against the C# entity."},{"label":"Safety","value":"Unknown field, unknown operator, or malformed JSON → false (not met) + one logged warning. Never crashes."}]},{"heading":"i18n wiring","items":[{"label":"Keys not text","value":"Display Name Key & Missing Message Key are translation keys. Matching entries must exist in en.json (and es.json for 100% parity)."},{"label":"Missing translation","value":"Falls back to the raw key token in the chip — your signal the wiring is incomplete."}]},{"heading":"Routes & gating","items":[{"label":"/admin/lead-sources","value":"Lead Sources catalog. CAP-O2C-LEAD. Create/Update: Admin, Manager. Delete: Admin."},{"label":"/admin/icp-rubrics","value":"ICP rubrics + dimensions. CAP-O2C-LEAD. Admin, Manager (Delete: Admin)."},{"label":"/admin/entity-completeness","value":"Completeness requirement rows. Admin only."}]}]}"""
        });

        // ── Lead Scoring Admin Knowledge Check (Quiz) ─────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Scoring Admin Knowledge Check",
            Slug = "lead-scoring-quiz",
            Summary = "Test your understanding of Lead Sources, ICP rubrics and weighted dimensions, Match Spec JSON, and Entity Completeness predicates.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 7,
            AppRoutes = """["/admin/lead-sources","/admin/icp-rubrics","/admin/entity-completeness"]""",
            Tags = """["lead-scoring","quiz","admin"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ls1","text":"Why can't you change a Lead Source's Code after it's created?","options":[{"id":"a","text":"The Code is the stable natural key that imports, web forms, and referrer URLs bind to — changing it would silently break that attribution","isCorrect":true},{"id":"b","text":"The Code is encrypted and the system has no way to decrypt it"},{"id":"c","text":"Codes are reused across installs and must stay globally unique"},{"id":"d","text":"It can be changed — the field is just hidden by default"}],"explanation":"The Code is the immutable natural key. Bulk-import pipelines map columns to a source Code, and web forms / referrer URLs carry it; historical leads point at it. If it could change, every binding would break. The edit dialog disables the Code field for exactly this reason. Choose it carefully at create time."},{"id":"ls2","text":"Where does a Lead Source's Quality Score come from?","options":[{"id":"a","text":"An admin types it into the source's edit dialog"},{"id":"b","text":"It is auto-computed nightly from the disposition outcomes of that source's leads","isCorrect":true},{"id":"c","text":"It is pulled from the list provider's API"},{"id":"d","text":"It is the simple count of leads attributed to the source"}],"explanation":"Quality Score is read-only and computed by a nightly job. Every source starts at 50; converted leads add points, engaged leads add fewer, bad-data/suppressed leads subtract, and lost leads subtract a little. Only leads from roughly the last 180 days count, which makes the score 'rolling'. It is never typed by hand."},{"id":"ls3","text":"You try to delete a Lead Source that has 40 leads attributed to it. What happens, and what should you do instead?","options":[{"id":"a","text":"It deletes and the 40 leads lose their source — that's expected"},{"id":"b","text":"The server blocks the delete; you should deactivate the source instead so historical attribution survives","isCorrect":true},{"id":"c","text":"It deletes and the 40 leads are reassigned to the default source"},{"id":"d","text":"Nothing happens — sources can never be deleted"}],"explanation":"Delete is blocked with an error when leads are linked, as a guard rail. The right action is to set the Active toggle off (deactivate): the source disappears from new-intake choices but stays attached to its historical leads, preserving attribution and the Quality Score. Only never-used mistake sources can be hard-deleted."},{"id":"ls4","text":"Which rubric does the nightly ICP scoring job actually use?","options":[{"id":"a","text":"All Active rubrics, averaging the scores together"},{"id":"b","text":"The single rubric that is both Active and Default","isCorrect":true},{"id":"c","text":"The most recently edited rubric"},{"id":"d","text":"Whichever rubric has the most dimensions"}],"explanation":"The job uses exactly one rubric: the one flagged both Active and Default. The server enforces a single default — marking a new rubric default automatically un-defaults the previous one. If no rubric is Active+Default (or it has no dimensions / no positive weight), the job skips and writes no scores."},{"id":"ls5","text":"An ICP dimension's Match Spec is the JSON array [\"aerospace\",\"defense\"]. How is a lead matched against it?","options":[{"id":"a","text":"The lead's industry must equal exactly 'aerospace' or 'defense'"},{"id":"b","text":"A case-insensitive substring search of those strings across the lead's company name, source, email, and account fields — any hit counts","isCorrect":true},{"id":"c","text":"The lead must contain BOTH strings to match"},{"id":"d","text":"Arrays are not a valid Match Spec shape and are ignored"}],"explanation":"A string array is a case-insensitive SUBSTRING match. The job tests each string against the lead's company name, source, email, and (if on an Account) the account's industry, state, size bracket, and name. If any one string is found inside any one of those fields, the dimension hits and its weight is added. For an exact field match instead, use the keyed object form like { \"industries\": [...] }."},{"id":"ls6","text":"How is a lead's final 0–100 IcpScore computed from the dimensions?","options":[{"id":"a","text":"It's the count of dimensions that matched"},{"id":"b","text":"Sum the weights of matching dimensions, divide by the sum of all positive weights, multiply by 100, and clamp to 0–100","isCorrect":true},{"id":"c","text":"It's the single highest weight among matching dimensions"},{"id":"d","text":"Each dimension is scored 0–100 separately and they're averaged"}],"explanation":"The job adds the Weight of every dimension that matches, divides by the maximum achievable (the sum of positive weights), scales to 100, and clamps to 0–100. Because the denominator scales with the weights, only the RELATIVE weights matter. Negative weights can penalize an anti-fit and push a lead toward 0."},{"id":"ls7","text":"After you edit a default rubric's dimension weights, when do lead scores reflect the change?","options":[{"id":"a","text":"Immediately — scores recompute the moment you save"},{"id":"b","text":"On the next nightly scoring run, which rewrites Lead.IcpScore for active leads","isCorrect":true},{"id":"c","text":"Only when a rep opens each lead"},{"id":"d","text":"Never — existing scores are frozen once written"}],"explanation":"Scoring is not real-time. Lead.IcpScore is a cached column written by the nightly job. Editing a rubric today means the new weights take effect on the next run, which recomputes scores for every active (non-Converted, non-Lost) lead and re-orders the work-queue."},{"id":"ls8","text":"In the Entity Completeness admin, what is the Requirement Id field for?","options":[{"id":"a","text":"It's an auto-generated database primary key you can't edit"},{"id":"b","text":"A stable id for one specific requirement within an (Entity Type, Capability) pair, so a capability can declare several discrete checks that each show up individually","isCorrect":true},{"id":"c","text":"It points at the lead source the requirement came from"},{"id":"d","text":"It's the i18n key used to render the chip label"}],"explanation":"Entity Type + Capability Code + Requirement Id are unique together. The Requirement Id (e.g. 'tax-id', 'payment-terms') lets one capability declare multiple discrete requirements on the same entity type, each surfacing as its own line in the completeness chip's missing-fields list. You add several rows rather than cramming everything into one predicate."},{"id":"ls9","text":"A completeness vendor must have a tax id AND at least one address. Which predicate expresses that?","options":[{"id":"a","text":"{ \"type\": \"any\", \"predicates\": [ {\"type\":\"fieldPresent\",\"field\":\"taxId\"}, {\"type\":\"relationExists\",\"field\":\"addresses\",\"minCount\":1} ] }"},{"id":"b","text":"{ \"type\": \"all\", \"predicates\": [ {\"type\":\"fieldPresent\",\"field\":\"taxId\"}, {\"type\":\"relationExists\",\"field\":\"addresses\",\"minCount\":1} ] }","isCorrect":true},{"id":"c","text":"{ \"type\": \"fieldEquals\", \"field\": \"taxId\", \"value\": \"addresses\" }"},{"id":"d","text":"{ \"type\": \"fieldPresent\", \"field\": \"taxId,addresses\" }"}],"explanation":"Use 'all' to require every nested predicate to pass (logical AND). 'any' would pass if either one were satisfied (OR). Here fieldPresent checks the tax id is set and relationExists checks the addresses collection has at least one item. Field names are written in camelCase."},{"id":"ls10","text":"What happens if a completeness predicate references an unknown field or contains malformed JSON?","options":[{"id":"a","text":"The completeness chip throws an error and fails to render"},{"id":"b","text":"It safely evaluates to false (the requirement counts as not met) and logs one warning","isCorrect":true},{"id":"c","text":"The requirement is automatically deleted"},{"id":"d","text":"It evaluates to true so the record isn't blocked"}],"explanation":"The predicate engine short-circuits unknown fields, unknown operators, and malformed JSON to false, emitting a single warning. The record simply looks incomplete (the requirement appears in the missing list) until you fix the predicate. It never crashes the chip and never silently passes."},{"id":"ls11","text":"On a completeness row, the chip shows the raw token 'entityCompleteness.fields.taxId' instead of 'Tax ID'. Why?","options":[{"id":"a","text":"The predicate is invalid"},{"id":"b","text":"The Display Name Key has no matching translation entry in the language files, so the UI falls back to the raw key","isCorrect":true},{"id":"c","text":"The capability is disabled"},{"id":"d","text":"The Sort Order is set too high"}],"explanation":"Display Name Key and Missing Message Key are i18n KEYS, not literal text. The chip renders the translated value only if a matching entry exists in en.json (and es.json for parity). A raw token on screen is the tell-tale sign the translation wiring is missing. Add the entries under the entityCompleteness.fields.* / entityCompleteness.messages.* prefixes."},{"id":"ls12","text":"Why does the Entity Completeness catalog ship empty?","options":[{"id":"a","text":"It's a bug — it should have default rows"},{"id":"b","text":"The requirements an install needs depend on which capabilities it has enabled, so admins author the rows that fit rather than fighting a pre-seeded set","isCorrect":true},{"id":"c","text":"Completeness rules are imported automatically from the accounting provider"},{"id":"d","text":"The rows are seeded only when the first vendor is created"}],"explanation":"Per the design choice, the catalog is empty on a fresh install. Because completeness requirements are scoped to capabilities, and every install turns on a different set of capabilities, a one-size-fits-all seed would be wrong for most installs. Admins add exactly the rows their enabled capabilities require."}]}"""
        });

        Log.Information("Seeded Lead Scoring training modules");
